// ── Public API ──────────────────────────────────────────────────────
function getSubscriptionItemsForMcc(mcc, profileId) {
  if (!mcc) return [];
  const key = String(mcc).padStart(4, '0');
  const pool = SUBSCRIPTION_CATALOG[key] || SUBSCRIPTION_CATALOG[String(mcc)];
  if (!pool) return [];
  const hash = (typeof hashProfile === 'function') ? hashProfile(profileId) : 0;
  return CATALOG_PRICES
    .filter(p => pool[p] && pool[p].length > 0)
    .map(price => ({ name: pool[price][hash % pool[price].length], price }));
}

function getSubscriptionCatalogSize(mcc) {
  const key = String(mcc).padStart(4, '0');
  const pool = SUBSCRIPTION_CATALOG[key] || SUBSCRIPTION_CATALOG[String(mcc)];
  if (!pool) return 0;
  return CATALOG_PRICES.filter(p => pool[p] && pool[p].length > 0).length;
}



